const response = $('Search Mentions').first().json;
const tweets = response.data || [];

// Filter to genuine questions (contain '?' or question words)
const questions = tweets.filter(t => {
  const text = t.text.toLowerCase();
  return text.includes('?') || text.includes('how') || text.includes('what') || text.includes('why') || text.includes('when') || text.includes('predict');
});

// Limit to max 3 per run to avoid spam
const limited = questions.slice(0, 3);

if (limited.length === 0) {
  return [{ json: { skip: true, reason: 'No genuine questions found' } }];
}

return limited.map(t => ({
  json: {
    skip: false,
    tweetId: t.id,
    tweetText: t.text,
    prompt: `Someone tweeted: '${t.text.replace(/'/g, "\\'")}'\n\nWrite a helpful, friendly reply from BTC Seer. Keep it short (max 240 chars). Don't be salesy, be genuinely helpful. If they asked about predictions, mention they can try @BTC_Seer_Bot on Telegram for free.`
  }
}));

const response = $('Claude Generate Reply').first().json;
const text = response.content[0].text.trim();
const tweetId = $('Has Questions?').first().json.tweetId;
return [{ json: { text, tweetId } }];

const reply = $('Extract Reply Text').first().json.text;
const tweetId = $('Extract Reply Text').first().json.tweetId;
const now = new Date().toISOString();
console.log(`[${now}] Auto-reply posted to tweet ${tweetId}: ${reply.substring(0, 80)}...`);
return [{ json: { status: 'replied', timestamp: now, inReplyTo: tweetId } }];
